from qiskit import QuantumCircuit

def build():
    qc = QuantumCircuit(2)
    qc.h(0)
    return qc

calls = {
    "A": lambda qc: qc.draw("text", initial_state=True),
    "B": lambda qc: qc.draw("text", with_initial_state=True),
    "C": lambda qc: qc.draw("text", plot_barriers=True),
    "D": lambda qc: qc.draw("text", vertical_compression="high"),
}
evidence = {}
proven = []
for k, fn in calls.items():
    try:
        txt = str(fn(build()))
        has_label = "|0>" in txt
        evidence[k] = f"rendered OK; initial-state label '|0>' present={has_label}"
        if has_label:
            proven.append(k)
    except Exception as e:
        evidence[k] = f"raised {type(e).__name__}: {str(e)[:90]}"

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"initial_state_drawing": str(build().draw('text', initial_state=True))},
})
